import{_ as s,o as e,c as i,a2 as n}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"GTPay 快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"gtpay/index.md","filePath":"gtpay/index.md","lastUpdated":1784433066000}'),t={name:"gtpay/index.md"};function p(l,a,d,o,c,h){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="gtpay-快速开始" tabindex="-1">GTPay 快速开始 <a class="header-anchor" href="#gtpay-快速开始" aria-label="Permalink to &quot;GTPay 快速开始&quot;">​</a></h1><p>GTPay 用于在 Minecraft 服务器内创建微信、支付宝收款订单。玩家下单后，收款码会显示在手中地图上；到账后自动执行点券或礼包奖励命令。</p><p>支持 Minecraft 1.12.2 到当前最新版。</p><p>GTPay支持本地、MySQL 和 Redis 三种订单存储。多台独立服务端使用同一收款主体和共享存储时，累计赞助、排行、礼包限制和领取记录可以统一统计。</p><h2 id="使用前准备" tabindex="-1">使用前准备 <a class="header-anchor" href="#使用前准备" aria-label="Permalink to &quot;使用前准备&quot;">​</a></h2><p>服主需要准备：</p><ul><li>已正常运行并完成授权的 GTCore。</li><li>有效的 GTPay 使用权限。</li><li>一台用于运行 <code>GT收款守护</code> 的安卓设备。</li><li>微信、支付宝个人收款码图片。</li><li>用于发放点券、权限组、物品或其他奖励的控制台命令。</li></ul><p>GTPay 不需要单独放置插件 JAR。服务器启动后由 GTCore 自动加载，配置目录仍然位于：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/GTPay/</span></span></code></pre></div><h2 id="开通商户" tabindex="-1">开通商户 <a class="header-anchor" href="#开通商户" aria-label="Permalink to &quot;开通商户&quot;">​</a></h2><p>使用购买 GTPay 时登记的 QQ 私聊机器人：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建GTPay 生存一区</span></span></code></pre></div><p>机器人会返回本服务器使用的：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>merchant_id</span></span>
<span class="line"><span>server_id</span></span>
<span class="line"><span>server_key</span></span>
<span class="line"><span>monitor_key</span></span></code></pre></div><p>一个 QQ 可以创建多个服务器。不同服务器使用不同名称，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建GTPay 生存一区</span></span>
<span class="line"><span>创建GTPay 生存二区</span></span>
<span class="line"><span>创建GTPay RPG一区</span></span></code></pre></div><p>忘记密钥时私聊机器人：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询GTPay</span></span>
<span class="line"><span>查询GTPay 生存一区</span></span></code></pre></div><p>同名服务器重复创建会返回原来的配置，不会自动更换密钥。</p><h2 id="第一次配置" tabindex="-1">第一次配置 <a class="header-anchor" href="#第一次配置" aria-label="Permalink to &quot;第一次配置&quot;">​</a></h2><ol><li>启动 Minecraft 服务器。</li><li>在服务器控制台输入：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtpay web open</span></span></code></pre></div><ol start="3"><li>在运行服务端的机器上打开控制台返回的本地管理页。</li><li>填写 <code>merchant_id</code>、<code>server_id</code>、<code>server_key</code>、<code>monitor_key</code>。</li><li>保存配置。</li><li>把收款码放入：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/GTPay/qrcode/wechat.png</span></span>
<span class="line"><span>plugins/GTPay/qrcode/alipay.png</span></span></code></pre></div><ol start="7"><li>在安卓设备启动 <code>GT收款守护</code>。</li><li>App 中填写 <code>merchant_id</code> 和 <code>monitor_key</code>。</li><li>授予通知使用权，确认 App 显示连接成功。</li></ol><p>管理页只用于本机配置，默认不会对外开放。配置完成后会在一段时间无操作后自动关闭，也可以执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gtpay web close</span></span></code></pre></div><h2 id="第一个点券订单" tabindex="-1">第一个点券订单 <a class="header-anchor" href="#第一个点券订单" aria-label="Permalink to &quot;第一个点券订单&quot;">​</a></h2><p>先在 <code>topup.yml</code> 中把奖励命令改成服务器实际使用的点券命令，例如：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;点券充值&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">scaled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">integer_only</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">min_amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.01</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">max_amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000000</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">commands</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[console] points give {player} {scaled_amount}&quot;</span></span></code></pre></div><p>保存后执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay reload</span></span></code></pre></div><p>玩家创建 10 元微信订单：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay buy 10 wechat</span></span></code></pre></div><p>创建 10 元支付宝订单：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay buy 10 alipay</span></span></code></pre></div><p>订单有效时间固定为 5 分钟。玩家手持付款地图时按 <code>Q</code> 会取消订单，执行 <code>/gtpay close</code> 也会取消当前订单。</p><h2 id="支付金额规则" tabindex="-1">支付金额规则 <a class="header-anchor" href="#支付金额规则" aria-label="Permalink to &quot;支付金额规则&quot;">​</a></h2><p>没有相同待支付订单时，10 元订单就是 10.00 元。</p><p>同一服务器、同一渠道、同一基础金额已经存在待支付订单时，GTPay 从最低可用分币开始分配：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.00</span></span>
<span class="line"><span>10.01</span></span>
<span class="line"><span>10.02</span></span>
<span class="line"><span>10.03</span></span></code></pre></div><p>已支付、已完成、已取消、已过期和异常订单不会继续占用金额。不是随机增加，也不会无故出现 10.90、1.65 这类大幅加价。</p><h2 id="配置文件" tabindex="-1">配置文件 <a class="header-anchor" href="#配置文件" aria-label="Permalink to &quot;配置文件&quot;">​</a></h2><p>首次启动后主要使用以下文件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>plugins/GTPay/</span></span>
<span class="line"><span>  config.yml</span></span>
<span class="line"><span>  gateway.yml</span></span>
<span class="line"><span>  message.yml</span></span>
<span class="line"><span>  topup.yml</span></span>
<span class="line"><span>  gifts.yml</span></span>
<span class="line"><span>  sponsorship.yml</span></span>
<span class="line"><span>  qrcode/</span></span>
<span class="line"><span>    wechat.png</span></span>
<span class="line"><span>    alipay.png</span></span>
<span class="line"><span>  gui/</span></span>
<span class="line"><span>    main.yml</span></span>
<span class="line"><span>    gifts.yml</span></span></code></pre></div><p>各文件用途：</p><table tabindex="0"><thead><tr><th>文件</th><th>用途</th></tr></thead><tbody><tr><td><code>config.yml</code></td><td>本地管理页、查询频率、支付渠道、收款码文件和存储方式</td></tr><tr><td><code>gateway.yml</code></td><td>商户与服务器密钥，可通过本地管理页填写</td></tr><tr><td><code>message.yml</code></td><td>玩家提示与帮助文本</td></tr><tr><td><code>topup.yml</code></td><td>点券充值及其发放命令</td></tr><tr><td><code>gifts.yml</code></td><td>独立礼包与固定价格</td></tr><tr><td><code>sponsorship.yml</code></td><td>永久、周、月、活动累计赞助奖励</td></tr><tr><td><code>gui/*.yml</code></td><td>多个自定义充值和礼包 GUI</td></tr></tbody></table><h2 id="文档入口" tabindex="-1">文档入口 <a class="header-anchor" href="#文档入口" aria-label="Permalink to &quot;文档入口&quot;">​</a></h2><ul><li><a href="./setup">安装、商户与监听 App</a></li><li><a href="./config">配置文件</a></li><li><a href="./purchases">点券与礼包</a></li><li><a href="./sponsorship">累计赞助</a></li><li><a href="./gui">GUI 配置</a></li><li><a href="./commands">命令与权限</a></li><li><a href="./placeholders">PAPI 变量</a></li><li><a href="./faq">订单状态与常见问题</a></li></ul>`,49)])])}const k=s(t,[["render",p]]);export{g as __pageData,k as default};
